#!/usr/bin/env node

const fs = require('fs');
const path = require('path');
const { execSync } = require('child_process');
const { loadRecipeRelations } = require('../recipes/recipe-relations');

const GENERATED_NOTICE = [
	'<!--',
	'This file is auto-generated by scripts/hooks/generate-hook-docs.js.',
	'Do not edit manually.',
	'-->',
	'',
].join('\n');

function getDefaultNamingRules() {
	return {
		allowedPrefixes: ['graphql_'],
		allowedHookNamePattern: '^[a-z0-9_]+$',
		minSegmentsAfterPrefix: 2,
		lowSpecificityAllowlist: [],
		dynamicNamePattern: '^["\']?graphql_',
		legacyAllowedPrefixes: ['pre_graphql_', 'register_graphql_'],
		deprecatedPrefixes: ['wpgraphql_', 'wp_graphql_', 'init_graphql_'],
		coreHookAllowlist: [],
	};
}

function getDefaultLegacyHooks() {
	return {};
}

function parseArgs() {
	const args = {};

	process.argv.slice(2).forEach((arg) => {
		const [rawKey, ...valueParts] = arg.replace(/^--/, '').split('=');
		const value = valueParts.join('=');
		args[rawKey] = value === '' ? true : value;
	});

	return args;
}

function readJson(filePath) {
	if (!fs.existsSync(filePath)) {
		throw new Error(`File not found: ${filePath}`);
	}

	return JSON.parse(fs.readFileSync(filePath, 'utf8'));
}

function escapeMdxText(value) {
	if (typeof value !== 'string') {
		return '';
	}

	return value.replace(/[{}]/g, '\\$&');
}

function normalizeRepoUrl(repoUrl) {
	if (!repoUrl || typeof repoUrl !== 'string') {
		return null;
	}

	const trimmed = repoUrl.trim();
	if (!trimmed) {
		return null;
	}

	if (trimmed.startsWith('git@github.com:')) {
		return trimmed
			.replace(/^git@github\.com:/, 'https://github.com/')
			.replace(/\.git$/, '');
	}

	if (trimmed.startsWith('https://github.com/')) {
		return trimmed.replace(/\.git$/, '');
	}

	return trimmed.replace(/\.git$/, '');
}

function resolveRepositoryUrl({ args, pluginConfig, repoRoot }) {
	const fromArgs = normalizeRepoUrl(args['repo-url']);
	if (fromArgs) {
		return fromArgs;
	}

	const fromConfig = normalizeRepoUrl(pluginConfig.repositoryUrl);
	if (fromConfig) {
		return fromConfig;
	}

	try {
		const remoteUrl = execSync('git remote get-url origin', {
			cwd: repoRoot,
			encoding: 'utf8',
			stdio: ['ignore', 'pipe', 'ignore'],
		}).trim();
		return normalizeRepoUrl(remoteUrl);
	} catch (_error) {
		return null;
	}
}

function resolveRepositoryRef({ args, pluginConfig, repoRoot }) {
	const fromArgs = typeof args['repo-ref'] === 'string' ? args['repo-ref'].trim() : '';
	if (fromArgs) {
		return fromArgs;
	}

	const fromConfig =
		typeof pluginConfig.repositoryRef === 'string' ? pluginConfig.repositoryRef.trim() : '';
	if (fromConfig) {
		return fromConfig;
	}

	try {
		const originHead = execSync('git symbolic-ref refs/remotes/origin/HEAD', {
			cwd: repoRoot,
			encoding: 'utf8',
			stdio: ['ignore', 'pipe', 'ignore'],
		}).trim();
		const branch = originHead.split('/').pop();
		return branch || 'main';
	} catch (_error) {
		return 'main';
	}
}

function buildRepositoryFileUrl({ repositoryUrl, repositoryRef, filePath, line }) {
	if (!repositoryUrl || !repositoryRef || !filePath) {
		return null;
	}

	const encodedSegments = filePath
		.split('/')
		.map((segment) => encodeURIComponent(segment))
		.join('/');
	const lineAnchor = line ? `#L${line}` : '';
	return `${repositoryUrl}/blob/${encodeURIComponent(repositoryRef)}/${encodedSegments}${lineAnchor}`;
}

function normalizeLifecycleStatus(status) {
	if (status === 'deprecated' || status === 'removed' || status === 'active') {
		return status;
	}
	return null;
}

function normalizeLegacyEntry(entry, pluginSlug) {
	if (!entry || typeof entry !== 'object') {
		return null;
	}

	const kind = entry.kind === 'action' || entry.kind === 'filter' ? entry.kind : null;
	const name = typeof entry.name === 'string' && entry.name.trim() ? entry.name.trim() : null;
	if (!kind || !name) {
		return null;
	}

	const deprecatedIn =
		typeof entry.deprecatedIn === 'string' && entry.deprecatedIn.trim()
			? entry.deprecatedIn.trim()
			: null;
	const removedIn =
		typeof entry.removedIn === 'string' && entry.removedIn.trim() ? entry.removedIn.trim() : null;

	let status = normalizeLifecycleStatus(entry.status);
	if (!status) {
		status = removedIn ? 'removed' : deprecatedIn ? 'deprecated' : 'active';
	}

	const replacement =
		typeof entry.replacement === 'string' && entry.replacement.trim()
			? entry.replacement.trim()
			: null;
	const message =
		typeof entry.message === 'string' && entry.message.trim() ? entry.message.trim() : null;

	return {
		pluginSlug,
		name,
		kind,
		description:
			typeof entry.description === 'string' && entry.description.trim()
				? entry.description.trim()
				: '',
		group:
			typeof entry.group === 'string' && entry.group.trim() ? entry.group.trim() : 'uncategorized',
		since: typeof entry.since === 'string' && entry.since.trim() ? entry.since.trim() : null,
		file:
			typeof entry.file === 'string' && entry.file.trim() ? entry.file.trim() : '__legacy_registry__',
		line: Number.isInteger(entry.line) ? entry.line : null,
		lifecycle: {
			status,
			deprecatedIn,
			removedIn,
			replacement,
			message,
			source: 'legacy_registry',
		},
	};
}

function loadLegacyHooks(legacyHooksPath, pluginSlug) {
	if (!legacyHooksPath || !fs.existsSync(legacyHooksPath)) {
		return [];
	}

	const payload = readJson(legacyHooksPath);
	const byPlugin = payload && typeof payload === 'object' ? payload[pluginSlug] : null;
	const rawEntries = Array.isArray(byPlugin) ? byPlugin : [];

	return rawEntries
		.map((entry) => normalizeLegacyEntry(entry, pluginSlug))
		.filter(Boolean);
}

function ensureDir(dirPath) {
	if (!fs.existsSync(dirPath)) {
		fs.mkdirSync(dirPath, { recursive: true });
	}
}

function listMarkdownFiles(dirPath) {
	if (!fs.existsSync(dirPath)) {
		return [];
	}

	return fs
		.readdirSync(dirPath)
		.filter((name) => name.endsWith('.md'))
		.map((name) => path.join(dirPath, name));
}

function walkPhpFiles(entryPath, acc = []) {
	if (!fs.existsSync(entryPath)) {
		return acc;
	}

	const stat = fs.statSync(entryPath);
	if (stat.isFile() && entryPath.endsWith('.php')) {
		acc.push(entryPath);
		return acc;
	}

	if (stat.isDirectory()) {
		const children = fs.readdirSync(entryPath);
		children.forEach((child) => {
			walkPhpFiles(path.join(entryPath, child), acc);
		});
	}

	return acc;
}

function parseDocblock(rawDocblock) {
	if (!rawDocblock) {
		return {
			description: '',
			since: null,
			hookGroup: null,
			hookSource: null,
			params: [],
		};
	}

	const lines = rawDocblock
		.replace(/^\/\*\*/, '')
		.replace(/\*\/$/, '')
		.split('\n')
		.map((line) => line.replace(/^\s*\*\s?/, '').trimEnd());

	const descriptionLines = [];
	const params = [];
	let since = null;
	let hookGroup = null;
	let hookSource = null;
	let inTags = false;

	lines.forEach((line) => {
		const trimmed = line.trim();
		if (trimmed.startsWith('@')) {
			inTags = true;
		}

		if (!inTags && trimmed !== '') {
			descriptionLines.push(trimmed);
		}

		const paramMatch = trimmed.match(/^@param\s+(\S+)\s+(\$\S+)\s*(.*)$/);
		if (paramMatch) {
			params.push({
				type: paramMatch[1],
				name: paramMatch[2],
				description: paramMatch[3] || '',
			});
		}

		const sinceMatch = trimmed.match(/^@since\s+(.+)$/);
		if (sinceMatch) {
			since = sinceMatch[1].trim();
		}

		const hookGroupMatch = trimmed.match(/^@hookGroup\s+([a-z0-9_-]+)$/i);
		if (hookGroupMatch) {
			hookGroup = hookGroupMatch[1].toLowerCase();
		}

		const hookSourceMatch = trimmed.match(/^@hookSource\s+(core|wpgraphql)$/i);
		if (hookSourceMatch) {
			hookSource = hookSourceMatch[1].toLowerCase();
		}
	});

	return {
		description: descriptionLines.join(' ').trim(),
		since,
		hookGroup,
		hookSource,
		params,
	};
}

function getLineNumber(content, index) {
	return content.slice(0, index).split('\n').length;
}

function getEnclosingSymbol(content, index) {
	const before = content.slice(0, index);
	const classRegex =
		/(^|\n)\s*(?:abstract\s+|final\s+)?(?:class|trait|interface)\s+([A-Za-z_][A-Za-z0-9_]*)\b/g;
	const functionRegex =
		/(^|\n)\s*(?:(?:public|protected|private)\s+)?(?:(?:static|final|abstract)\s+)*function\s+&?\s*([A-Za-z_][A-Za-z0-9_]*)\s*\(/g;

	let className = null;
	let classMatch = classRegex.exec(before);
	while (classMatch) {
		className = classMatch[2];
		classMatch = classRegex.exec(before);
	}

	let functionName = null;
	let functionMatch = functionRegex.exec(before);
	while (functionMatch) {
		functionName = functionMatch[2];
		functionMatch = functionRegex.exec(before);
	}

	if (functionName) {
		return className ? `${className}::${functionName}()` : `${functionName}()`;
	}

	return null;
}

function extractCallAt(content, functionName, startIndex) {
	const functionIndex = content.indexOf(functionName, startIndex);
	if (functionIndex === -1) {
		return null;
	}

	let i = functionIndex + functionName.length;
	while (i < content.length && /\s/.test(content[i])) {
		i++;
	}

	if (content[i] !== '(') {
		return null;
	}

	const openParenIndex = i;
	let depth = 0;
	let inString = null;
	let isEscaped = false;

	for (let cursor = openParenIndex; cursor < content.length; cursor++) {
		const char = content[cursor];

		if (inString) {
			if (!isEscaped && char === inString) {
				inString = null;
			}
			isEscaped = !isEscaped && char === '\\';
			continue;
		}

		if (char === '"' || char === '\'') {
			inString = char;
			isEscaped = false;
			continue;
		}

		if (char === '(') {
			depth++;
		} else if (char === ')') {
			depth--;
			if (depth === 0) {
				const argsSource = content.slice(openParenIndex + 1, cursor);

				let semicolonIndex = cursor + 1;
				while (semicolonIndex < content.length && /\s/.test(content[semicolonIndex])) {
					semicolonIndex++;
				}

				if (content[semicolonIndex] !== ';') {
					return null;
				}

				return {
					functionName,
					functionIndex,
					argsSource,
					callSource: content.slice(functionIndex, semicolonIndex + 1).trim(),
					endIndex: semicolonIndex,
					line: getLineNumber(content, functionIndex),
				};
			}
		}
	}

	return null;
}

function splitTopLevelArgs(argsSource) {
	const args = [];
	let current = '';
	let depthParen = 0;
	let depthBracket = 0;
	let depthBrace = 0;
	let inString = null;
	let isEscaped = false;

	for (let i = 0; i < argsSource.length; i++) {
		const char = argsSource[i];

		if (inString) {
			current += char;
			if (!isEscaped && char === inString) {
				inString = null;
			}
			isEscaped = !isEscaped && char === '\\';
			continue;
		}

		if (char === '"' || char === '\'') {
			inString = char;
			isEscaped = false;
			current += char;
			continue;
		}

		if (char === '(') {
			depthParen++;
			current += char;
			continue;
		}
		if (char === ')') {
			depthParen--;
			current += char;
			continue;
		}
		if (char === '[') {
			depthBracket++;
			current += char;
			continue;
		}
		if (char === ']') {
			depthBracket--;
			current += char;
			continue;
		}
		if (char === '{') {
			depthBrace++;
			current += char;
			continue;
		}
		if (char === '}') {
			depthBrace--;
			current += char;
			continue;
		}

		if (char === ',' && depthParen === 0 && depthBracket === 0 && depthBrace === 0) {
			args.push(current.trim());
			current = '';
			continue;
		}

		current += char;
	}

	if (current.trim()) {
		args.push(current.trim());
	}

	return args;
}

function parseHookNameExpression(firstArg) {
	if (!firstArg) {
		return {
			name: null,
			isDynamic: true,
			rawExpression: '',
		};
	}

	const singleQuoted = firstArg.match(/^'([^']+)'$/);
	if (singleQuoted) {
		return {
			name: singleQuoted[1],
			isDynamic: false,
			rawExpression: firstArg,
		};
	}

	const doubleQuoted = firstArg.match(/^"([^"]+)"$/);
	if (doubleQuoted) {
		const value = doubleQuoted[1];
		const hasInterpolation = /\$|\{/.test(value);
		return {
			name: hasInterpolation ? value : value,
			isDynamic: hasInterpolation,
			rawExpression: firstArg,
		};
	}

	return {
		name: firstArg,
		isDynamic: true,
		rawExpression: firstArg,
	};
}

function extractLiteralString(value) {
	if (typeof value !== 'string') {
		return null;
	}

	const singleQuoted = value.match(/^'([^']+)'$/);
	if (singleQuoted) {
		return singleQuoted[1];
	}

	const doubleQuoted = value.match(/^"([^"]+)"$/);
	if (doubleQuoted) {
		return doubleQuoted[1];
	}

	return null;
}

function normalizeDeprecatedCallMetadata(args = []) {
	const deprecatedIn = extractLiteralString(args[2] || '');
	const replacement = extractLiteralString(args[3] || '');
	const message = extractLiteralString(args[4] || '');

	return {
		status: 'deprecated',
		deprecatedIn,
		removedIn: null,
		replacement,
		message,
		source: 'deprecated_call',
	};
}

function getNearestDocblock(content, functionIndex) {
	function stripIgnorableInterveningText(value) {
		return value
			.replace(/\/\*[\s\S]*?\*\//g, '')
			.replace(/^\s*\/\/.*$/gm, '')
			.replace(/^\s*#.*$/gm, '')
			.trim();
	}

	let searchFrom = functionIndex;
	const lineStart = content.lastIndexOf('\n', functionIndex - 1) + 1;

	while (searchFrom > 0) {
		const docblockStart = content.lastIndexOf('/**', searchFrom);
		if (docblockStart === -1) {
			return null;
		}

		const docblockEnd = content.indexOf('*/', docblockStart);
		if (docblockEnd === -1 || docblockEnd > functionIndex) {
			searchFrom = docblockStart - 1;
			continue;
		}

		const between = content.slice(docblockEnd + 2, lineStart);
		if (stripIgnorableInterveningText(between) !== '') {
			return null;
		}

		return content.slice(docblockStart, docblockEnd + 2).trim();
	}

	return null;
}

function loadSnippets(snippetsDir) {
	if (!fs.existsSync(snippetsDir)) {
		return {
			byHookName: {},
			total: 0,
		};
	}

	const files = fs
		.readdirSync(snippetsDir)
		.filter((file) => file.endsWith('.md') || file.endsWith('.mdx'));

	const byHookName = {};

	files.forEach((fileName) => {
		const fullPath = path.join(snippetsDir, fileName);
		const content = fs.readFileSync(fullPath, 'utf8');
		const frontmatterMatch = content.match(/^---\n([\s\S]*?)\n---\n?/);

		if (!frontmatterMatch) {
			return;
		}

		const frontmatter = parseFrontmatter(frontmatterMatch[1]);
		const hookNames = Array.isArray(frontmatter.hookNames) ? frontmatter.hookNames : [];
		const title = typeof frontmatter.title === 'string' ? frontmatter.title : fileName;
		const relativePath = path.relative(process.cwd(), fullPath);

		hookNames.forEach((hookName) => {
			if (!byHookName[hookName]) {
				byHookName[hookName] = [];
			}

			byHookName[hookName].push({
				title,
				path: relativePath,
			});
		});
	});

	return {
		byHookName,
		total: files.length,
	};
}

function parseFrontmatter(source) {
	const result = {};
	const lines = source.split('\n');
	let currentArrayKey = null;

	lines.forEach((line) => {
		const trimmed = line.trim();
		if (!trimmed || trimmed.startsWith('#')) {
			return;
		}

		if (trimmed.startsWith('- ') && currentArrayKey) {
			result[currentArrayKey].push(trimmed.replace(/^- /, '').trim());
			return;
		}

		const keyValueMatch = trimmed.match(/^([A-Za-z0-9_]+):\s*(.*)$/);
		if (!keyValueMatch) {
			currentArrayKey = null;
			return;
		}

		const key = keyValueMatch[1];
		const rawValue = keyValueMatch[2].trim();

		if (rawValue === '') {
			result[key] = [];
			currentArrayKey = key;
			return;
		}

		currentArrayKey = null;
		if (rawValue.startsWith('[') && rawValue.endsWith(']')) {
			result[key] = rawValue
				.slice(1, -1)
				.split(',')
				.map((item) => item.trim().replace(/^['"]|['"]$/g, ''))
				.filter(Boolean);
			return;
		}

		result[key] = rawValue.replace(/^['"]|['"]$/g, '');
	});

	return result;
}

function getDefaultGroup(groups) {
	return groups.find((group) => group.id === 'uncategorized') || groups[0];
}

function assignGroup(hook, groups) {
	if (hook.docblock.hookGroup) {
		const explicitGroup = groups.find((group) => group.id === hook.docblock.hookGroup);
		if (explicitGroup) {
			return {
				group: explicitGroup,
				source: 'explicit',
			};
		}

		return {
			group: getDefaultGroup(groups),
			source: 'invalid',
		};
	}

	if (typeof hook.name !== 'string' || hook.isDynamic) {
		return {
			group: getDefaultGroup(groups),
			source: 'fallback',
		};
	}

	for (const group of groups) {
		const patterns = Array.isArray(group.match) ? group.match : [];
		for (const pattern of patterns) {
			const regex = new RegExp(pattern);
			if (regex.test(hook.name)) {
				return {
					group,
					source: 'fallback',
				};
			}
		}
	}

	return {
		group: getDefaultGroup(groups),
		source: 'fallback',
	};
}

function buildHookRecord({
	pluginSlug,
	hook,
	groupAssignment,
	sourceType,
	relativeFilePath,
	snippetMap,
	repositoryUrl,
	repositoryRef,
}) {
	const relatedSnippets = snippetMap[hook.name] || [];

	return {
		pluginSlug,
		name: hook.name,
		kind: hook.kind,
		group: groupAssignment.group.id,
		groupLabel: groupAssignment.group.label,
		groupSource: groupAssignment.source,
		sourceType,
		emitter: hook.emitter,
		enclosingSymbol: hook.enclosingSymbol || null,
		file: relativeFilePath,
		line: hook.line,
		repositoryUrl,
		repositoryRef,
		description: hook.docblock.description,
		params: hook.docblock.params,
		argumentCount: hook.argumentCount || 0,
		docblockParamCount: hook.docblock.params.length,
		since: hook.docblock.since,
		hookGroup: hook.docblock.hookGroup,
		isDynamic: hook.isDynamic,
		rawExpression: hook.rawExpression,
		sourceCall: hook.sourceCall || null,
		relatedSnippets,
		lifecycle:
			hook.lifecycle ||
			({
				status: 'active',
				deprecatedIn: null,
				removedIn: null,
				replacement: null,
				message: null,
				source: null,
			}),
	};
}

function inferHookSourceType(hook, namingRules) {
	if (hook.docblock.hookSource === 'core' || hook.docblock.hookSource === 'wpgraphql') {
		return hook.docblock.hookSource;
	}

	const hookName = typeof hook.name === 'string' ? hook.name : '';
	const raw = hook.rawExpression || '';
	const coreAllowlist = Array.isArray(namingRules.coreHookAllowlist)
		? namingRules.coreHookAllowlist
		: [];

	if (hookName && coreAllowlist.includes(hookName)) {
		return 'core';
	}

	if (hook.isDynamic) {
		if (/graphql_|graphiql_/i.test(raw)) {
			return 'wpgraphql';
		}
		return 'core';
	}

	if (/graphql|graphiql/i.test(hookName)) {
		return 'wpgraphql';
	}

	return 'core';
}

function slugFromHookName(hookName) {
	return hookName.toLowerCase().replace(/[^a-z0-9_-]+/g, '-');
}

function collectHookReferences(hooks) {
	const referencesByKey = new Map();

	hooks.forEach((hook) => {
		if (hook.isDynamic || !hook.name || !hook.kind) {
			return;
		}

		const key = `${hook.kind}:${hook.name}`;
		const existing = referencesByKey.get(key) || [];
		const reference = {
			file: hook.file,
			line: hook.line || null,
			symbol: hook.enclosingSymbol || null,
			emitter: hook.emitter || null,
		};

		if (
			reference.file === '__legacy_registry__' ||
			existing.some(
				(item) =>
					item.file === reference.file &&
					item.line === reference.line &&
					item.symbol === reference.symbol &&
					item.emitter === reference.emitter
			)
		) {
			return;
		}

		existing.push(reference);
		referencesByKey.set(key, existing);
	});

	referencesByKey.forEach((references, key) => {
		referencesByKey.set(
			key,
			references.sort((a, b) => {
				const fileCompare = a.file.localeCompare(b.file);
				if (fileCompare !== 0) {
					return fileCompare;
				}
				return (a.line || 0) - (b.line || 0);
			})
		);
	});

	return referencesByKey;
}

function attachRelatedReferences(hooks) {
	const referencesByKey = collectHookReferences(hooks);

	return hooks.map((hook) => {
		if (hook.isDynamic || !hook.name || !hook.kind) {
			return {
				...hook,
				relatedReferences: [],
			};
		}

		const key = `${hook.kind}:${hook.name}`;
		return {
			...hook,
			relatedReferences: referencesByKey.get(key) || [],
		};
	});
}

function renderHookDoc(hook) {
	const title = hook.name || hook.rawExpression || 'unknown_hook';
	const params = hook.params || [];
	const snippets = hook.relatedSnippets || [];
	const references = hook.relatedReferences || [];
	const relatedRecipes = hook.relatedRecipes || [];
	const signature = hook.sourceCall ? hook.sourceCall.replace(/\s+/g, ' ').trim() : null;
	const description = escapeMdxText(hook.description || 'No description available.');
	const lifecycle = hook.lifecycle || { status: 'active' };
	const statusLabel = lifecycle.status || 'active';

	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push('---');
	lines.push(`title: ${title}`);
	lines.push(`hookType: ${hook.kind}`);
	lines.push(`hookGroup: ${hook.group}`);
	lines.push(`plugin: ${hook.pluginSlug}`);
	lines.push('---');
	lines.push('');
	lines.push(`# ${title}`);
	lines.push('');
	if (statusLabel === 'deprecated' || statusLabel === 'removed') {
		const lifecycleVerb = statusLabel === 'removed' ? 'removed' : 'deprecated';
		const deprecatedVersion = lifecycle.deprecatedIn || 'Unknown';
		const deprecatedVersionLabel =
			deprecatedVersion !== 'Unknown' && /^\d/.test(deprecatedVersion)
				? `v${deprecatedVersion}`
				: deprecatedVersion;
		lines.push('> [!WARNING]');
		lines.push(
			`> This hook has been ${lifecycleVerb} since ${deprecatedVersionLabel} and should not be used for new integrations.`
		);
		if (lifecycle.replacement) {
			lines.push(`> Use \`${lifecycle.replacement}\` instead.`);
		}
		lines.push('');
	}

	if (signature) {
		lines.push('```php');
		lines.push(signature);
		lines.push('```');
		lines.push('');
	}

	lines.push(description);
	lines.push('');
	lines.push(`- **Type:** ${hook.kind}`);
	lines.push(`- **Group:** ${hook.groupLabel}`);
	lines.push(`- **Since:** ${hook.since || 'Unknown'}`);
	lines.push(`- **Source File:** \`${hook.file}\``);
	lines.push('');

	if (statusLabel === 'deprecated' || statusLabel === 'removed') {
		lines.push('## Lifecycle');
		lines.push('');
		lines.push(`- **Deprecated in:** ${lifecycle.deprecatedIn || 'Unknown'}`);
		if (statusLabel === 'removed') {
			lines.push(`- **Removed in:** ${lifecycle.removedIn || 'Unknown'}`);
		}
		if (lifecycle.replacement) {
			lines.push(`- **Replacement:** \`${lifecycle.replacement}\``);
		}
		if (lifecycle.message) {
			lines.push(`- **Notes:** ${escapeMdxText(lifecycle.message)}`);
		}
		lines.push('');
	}

	if (params.length > 0) {
		lines.push('## Parameters');
		lines.push('');
		params.forEach((param) => {
			lines.push(
				`- \`${param.name}\` (\`${param.type}\`): ${escapeMdxText(param.description || 'No description.')}`
			);
		});
		lines.push('');
	}

	const sourceUrl = buildRepositoryFileUrl({
		repositoryUrl: hook.repositoryUrl,
		repositoryRef: hook.repositoryRef,
		filePath: hook.file,
		line: hook.line,
	});
	if (sourceUrl || hook.sourceCall) {
		lines.push('## Source');
		lines.push('');
		if (sourceUrl) {
			const location = hook.line ? `${hook.file}:${hook.line}` : hook.file;
			lines.push(`- [\`${location}\`](${sourceUrl})`);
			lines.push('');
		}
		if (hook.sourceCall) {
			lines.push('```php');
			lines.push(hook.sourceCall);
			lines.push('```');
			lines.push('');
		}
	}

	if (references.length > 0) {
		lines.push('## Related');
		lines.push('');
		references.forEach((reference) => {
			const symbolLabel = reference.symbol ? `\`${reference.symbol}\`` : 'top-level code';
			const location = reference.line ? `${reference.file}:${reference.line}` : reference.file;
			const referenceUrl = buildRepositoryFileUrl({
				repositoryUrl: hook.repositoryUrl,
				repositoryRef: hook.repositoryRef,
				filePath: reference.file,
				line: reference.line,
			});
			const locationLabel = referenceUrl ? `[\`${location}\`](${referenceUrl})` : `\`${location}\``;
			lines.push(`- ${symbolLabel} in ${locationLabel}`);
		});
		lines.push('');
	}

	if (relatedRecipes.length > 0) {
		lines.push('## Recipes');
		lines.push('');
		relatedRecipes.forEach((recipe) => {
			lines.push(`- [${recipe.title}](${recipe.uri})`);
		});
		lines.push('');
	}

	if (snippets.length > 0) {
		lines.push('## Related Snippets');
		lines.push('');
		snippets.forEach((snippet) => {
			lines.push(`- [${snippet.title}](/${snippet.path})`);
		});
		lines.push('');
	}

	return lines.join('\n');
}

function groupHooks(hooks) {
	return hooks.reduce((acc, hook) => {
		if (!acc[hook.group]) {
			acc[hook.group] = [];
		}
		acc[hook.group].push(hook);
		return acc;
	}, {});
}

function renderIndexPage({ title, kind, hooks }) {
	const grouped = groupHooks(hooks);
	const orderedGroups = Object.keys(grouped).sort((a, b) => a.localeCompare(b));

	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push('---');
	lines.push(`title: ${title}`);
	lines.push('---');
	lines.push('');
	lines.push(`# ${title}`);
	lines.push('');

	if (hooks.length === 0) {
		lines.push('No hooks found.');
		lines.push('');
		return lines.join('\n');
	}

	orderedGroups.forEach((groupId) => {
		const groupHooksList = grouped[groupId];
		const label = groupHooksList[0]?.groupLabel || groupId;

		lines.push(`## ${label}`);
		lines.push('');
		groupHooksList
			.sort((a, b) => (a.name || '').localeCompare(b.name || ''))
			.forEach((hook) => {
				const slug = slugFromHookName(hook.name);
				const status = hook.lifecycle?.status;
				const statusSuffix =
					status === 'deprecated' ? ' _(deprecated)_' : status === 'removed' ? ' _(removed)_' : '';
				lines.push(`- [\`${hook.name}\`](/docs/${kind}/${slug})${statusSuffix}`);
			});
		lines.push('');
	});

	return lines.join('\n');
}

function analyzeHookNaming(hooks, namingRules) {
	const compiled = {
		namePattern: new RegExp(namingRules.allowedHookNamePattern),
		dynamicPattern: new RegExp(namingRules.dynamicNamePattern),
	};

	const prefixBuckets = {};
	const flaggedHooks = [];

	const wpgraphqlHooks = hooks.filter((hook) => hook.sourceType === 'wpgraphql');
	const activeHooks = wpgraphqlHooks.filter((hook) => {
		const status = hook.lifecycle?.status;
		return status !== 'deprecated' && status !== 'removed';
	});
	const staticHooks = wpgraphqlHooks.filter(
		(hook) =>
			!hook.isDynamic &&
			typeof hook.name === 'string' &&
			activeHooks.includes(hook)
	);
	const dynamicHooks = wpgraphqlHooks.filter((hook) => hook.isDynamic && activeHooks.includes(hook));

	function hasAllowedPrefix(name) {
		return namingRules.allowedPrefixes.some((prefix) => name.startsWith(prefix));
	}

	function hasLegacyAllowedPrefix(name) {
		return (namingRules.legacyAllowedPrefixes || []).some((prefix) =>
			name.startsWith(prefix)
		);
	}

	function isLowSpecificityAllowed(name) {
		return (namingRules.lowSpecificityAllowlist || []).includes(name);
	}

	function getDeprecatedPrefix(name) {
		return (namingRules.deprecatedPrefixes || []).find((prefix) =>
			name.startsWith(prefix)
		);
	}

	function getMigrationSuggestion(name) {
		if (name.startsWith('init_graphql_')) {
			return `graphql_init_${name.replace(/^init_graphql_/, '')}`;
		}
		if (name.startsWith('wpgraphql_')) {
			return `graphql_${name.replace(/^wpgraphql_/, '')}`;
		}
		if (name.startsWith('wp_graphql_')) {
			return `graphql_${name.replace(/^wp_graphql_/, '')}`;
		}
		return null;
	}

	function recordFlag(hook, code, severity, message, suggestion = null) {
		flaggedHooks.push({
			hook: hook.name,
			kind: hook.kind,
			file: hook.file,
			line: hook.line,
			code,
			severity,
			message,
			suggestion,
		});
	}

	staticHooks.forEach((hook) => {
		const name = hook.name;
		const topPrefix = name.includes('_') ? `${name.split('_')[0]}_` : name;
		prefixBuckets[topPrefix] = (prefixBuckets[topPrefix] || 0) + 1;

		const deprecatedPrefix = getDeprecatedPrefix(name);
		if (deprecatedPrefix) {
			recordFlag(
				hook,
				'deprecated_prefix',
				'warning',
				`Hook name uses deprecated prefix "${deprecatedPrefix}".`,
				getMigrationSuggestion(name)
					? `Consider migrating to "${getMigrationSuggestion(name)}".`
					: 'Prefer graphql_ prefix for new hook names.'
			);
		}

		if (!compiled.namePattern.test(name)) {
			recordFlag(
				hook,
				'invalid_characters',
				'warning',
				'Hook name contains characters outside the naming convention pattern.',
				'Use lowercase letters, numbers, and underscores only.'
			);
		}

		const allowed = hasAllowedPrefix(name) || hasLegacyAllowedPrefix(name);
		if (!allowed) {
			recordFlag(
				hook,
				'nonstandard_prefix',
				'warning',
				'Hook name does not use the expected WPGraphQL namespace prefix.',
				getMigrationSuggestion(name)
					? `Consider migrating to "${getMigrationSuggestion(name)}".`
					: 'Prefer the graphql_ prefix for new hooks.'
			);
		}

		const matchingPrefix =
			namingRules.allowedPrefixes.find((prefix) => name.startsWith(prefix)) ||
			namingRules.legacyAllowedPrefixes.find((prefix) => name.startsWith(prefix));

		if (matchingPrefix) {
			const remainder = name.slice(matchingPrefix.length);
			const segmentCount = remainder.split('_').filter(Boolean).length;
			if (segmentCount < namingRules.minSegmentsAfterPrefix && !isLowSpecificityAllowed(name)) {
				recordFlag(
					hook,
					'low_specificity',
					'warning',
					'Hook name has too few semantic segments after prefix.',
					'Use names that include both domain and event segments.'
				);
			}
		}
	});

	dynamicHooks.forEach((hook) => {
		if (!compiled.dynamicPattern.test(hook.rawExpression || '')) {
			recordFlag(
				hook,
				'dynamic_nonstandard_prefix',
				'warning',
				'Dynamic hook expression does not clearly map to an expected namespace prefix.',
				'Prefer dynamic hooks that still resolve to graphql_* or wpgraphql_* patterns.'
			);
		}
	});

	const topPrefixes = Object.entries(prefixBuckets)
		.sort((a, b) => b[1] - a[1])
		.slice(0, 10)
		.map(([prefix, count]) => ({ prefix, count }));

	const severityCounts = flaggedHooks.reduce(
		(acc, item) => {
			acc[item.severity] = (acc[item.severity] || 0) + 1;
			return acc;
		},
		{ warning: 0, error: 0 }
	);

	return {
		rules: namingRules,
		summary: {
			totalHooks: hooks.length,
			wpgraphqlHooks: wpgraphqlHooks.length,
			activeWpgraphqlHooks: activeHooks.length,
			coreHooks: hooks.filter((hook) => hook.sourceType === 'core').length,
			staticHooks: staticHooks.length,
			dynamicHooks: dynamicHooks.length,
			flaggedHooks: flaggedHooks.length,
			warnings: severityCounts.warning || 0,
			errors: severityCounts.error || 0,
		},
		topPrefixes,
		flaggedHooks,
	};
}

function renderNamingAuditMarkdown({ pluginSlug, audit }) {
	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push(`# Hook Naming Audit: ${pluginSlug}`);
	lines.push('');
	lines.push('## Summary');
	lines.push('');
	lines.push(`- Total hooks: ${audit.summary.totalHooks}`);
	lines.push(`- WPGraphQL hooks audited: ${audit.summary.wpgraphqlHooks}`);
	lines.push(`- Core hooks excluded from audit: ${audit.summary.coreHooks}`);
	lines.push(`- Static hooks: ${audit.summary.staticHooks}`);
	lines.push(`- Dynamic hooks: ${audit.summary.dynamicHooks}`);
	lines.push(`- Flagged hooks: ${audit.summary.flaggedHooks}`);
	lines.push(`- Warnings: ${audit.summary.warnings}`);
	lines.push(`- Errors: ${audit.summary.errors}`);
	lines.push('');
	lines.push('## Top Prefixes');
	lines.push('');
	if (audit.topPrefixes.length === 0) {
		lines.push('- No static hooks found.');
	} else {
		audit.topPrefixes.forEach((item) => {
			lines.push(`- \`${item.prefix}\`: ${item.count}`);
		});
	}
	lines.push('');
	lines.push('## Flagged Hooks');
	lines.push('');
	if (audit.flaggedHooks.length === 0) {
		lines.push('No naming convention flags detected.');
		lines.push('');
		return lines.join('\n');
	}

	audit.flaggedHooks.forEach((flag) => {
		lines.push(`### \`${flag.hook}\``);
		lines.push('');
		lines.push(`- Severity: ${flag.severity}`);
		lines.push(`- Code: ${flag.code}`);
		lines.push(`- Message: ${flag.message}`);
		lines.push(`- Source: \`${flag.file}\``);
		if (flag.suggestion) {
			lines.push(`- Suggestion: ${flag.suggestion}`);
		}
		lines.push('');
	});

	return lines.join('\n');
}

function renderLintMarkdown({ pluginSlug, lint }) {
	const lines = [];
	const warnings = Array.isArray(lint.warnings) ? lint.warnings : [];
	const errors = Array.isArray(lint.errors) ? lint.errors : [];
	const allItems = [...errors, ...warnings];

	const grouped = allItems.reduce((acc, item) => {
		const type = item.type || 'unknown';
		if (!acc[type]) {
			acc[type] = [];
		}
		acc[type].push(item);
		return acc;
	}, {});

	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push(`# Hook Lint Report: ${pluginSlug}`);
	lines.push('');
	lines.push('## Summary');
	lines.push('');
	lines.push(`- Errors: ${errors.length}`);
	lines.push(`- Warnings: ${warnings.length}`);
	lines.push(`- Total findings: ${allItems.length}`);
	lines.push('');

	if (allItems.length === 0) {
		lines.push('No lint findings detected.');
		lines.push('');
		return lines.join('\n');
	}

	lines.push('## Findings by Type');
	lines.push('');
	Object.keys(grouped)
		.sort((a, b) => a.localeCompare(b))
		.forEach((type) => {
			lines.push(`- \`${type}\`: ${grouped[type].length}`);
		});
	lines.push('');

	lines.push('## Findings');
	lines.push('');
	Object.keys(grouped)
		.sort((a, b) => a.localeCompare(b))
		.forEach((type) => {
			lines.push(`### \`${type}\``);
			lines.push('');
			grouped[type].forEach((item) => {
				const hook = item.hook || '(unknown hook)';
				lines.push(`- **Hook:** \`${hook}\``);
				lines.push(`  - Severity: ${errors.includes(item) ? 'error' : 'warning'}`);
				lines.push(`  - Message: ${item.message || 'No message provided.'}`);
				if (item.file) {
					lines.push(`  - Source: \`${item.file}\`${item.line ? ` (line ${item.line})` : ''}`);
				}
			});
			lines.push('');
		});

	return lines.join('\n');
}

function renderDeprecatedHooksMarkdown({ pluginSlug, hooks }) {
	const lines = [];
	lines.push(GENERATED_NOTICE.trimEnd());
	lines.push(`# Deprecated and Removed Hooks: ${pluginSlug}`);
	lines.push('');

	if (!hooks.length) {
		lines.push('No deprecated or removed hooks found.');
		lines.push('');
		return lines.join('\n');
	}

	lines.push('## Hooks');
	lines.push('');
	hooks.forEach((hook) => {
		const lifecycle = hook.lifecycle || {};
		lines.push(`### \`${hook.name}\``);
		lines.push('');
		lines.push(`- Type: ${hook.kind}`);
		lines.push(`- Status: ${lifecycle.status || 'deprecated'}`);
		lines.push(`- Deprecated in: ${lifecycle.deprecatedIn || 'Unknown'}`);
		if (lifecycle.removedIn) {
			lines.push(`- Removed in: ${lifecycle.removedIn}`);
		}
		if (lifecycle.replacement) {
			lines.push(`- Replacement: \`${lifecycle.replacement}\``);
		}
		lines.push(`- Source: \`${hook.file}\``);
		if (hook.occurrences && hook.occurrences > 1) {
			lines.push(`- Occurrences: ${hook.occurrences}`);
		}
		lines.push('');
	});

	return lines.join('\n');
}

function mergeLegacyHooks({ hooks, legacyEntries, groups, snippetMap, pluginSlug }) {
	if (!legacyEntries.length) {
		return hooks;
	}

	const groupById = new Map(groups.map((group) => [group.id, group]));
	const mergedHooks = [...hooks];
	const hooksByKey = mergedHooks.reduce((acc, hook) => {
		const key = `${hook.kind}:${hook.name}`;
		if (!acc.has(key)) {
			acc.set(key, []);
		}
		acc.get(key).push(hook);
		return acc;
	}, new Map());

	legacyEntries.forEach((entry) => {
		const key = `${entry.kind}:${entry.name}`;
		const existingHooks = hooksByKey.get(key) || [];
		const group = groupById.get(entry.group) || getDefaultGroup(groups);

		if (existingHooks.length > 0) {
			existingHooks.forEach((existing) => {
				const lifecycle = existing.lifecycle || {};
				existing.lifecycle = {
					status: entry.lifecycle.status || lifecycle.status || 'active',
					deprecatedIn:
						entry.lifecycle.deprecatedIn || lifecycle.deprecatedIn || existing.since || null,
					removedIn: entry.lifecycle.removedIn || lifecycle.removedIn || null,
					replacement: entry.lifecycle.replacement || lifecycle.replacement || null,
					message: entry.lifecycle.message || lifecycle.message || null,
					source: lifecycle.source || entry.lifecycle.source || null,
				};
				if (!existing.description && entry.description) {
					existing.description = entry.description;
				}
				if (!existing.since && entry.since) {
					existing.since = entry.since;
				}
			});
			return;
		}

		mergedHooks.push({
			pluginSlug,
			name: entry.name,
			kind: entry.kind,
			group: group.id,
			groupLabel: group.label,
			groupSource: 'legacy',
			sourceType: 'wpgraphql',
			emitter: 'legacy_registry',
			file: entry.file || '__legacy_registry__',
			line: entry.line || null,
			description:
				entry.description ||
				'This hook has been deprecated and is retained for documentation history.',
			params: [],
			since: entry.since,
			hookGroup: group.id,
			isDynamic: false,
			rawExpression: `'${entry.name}'`,
			relatedSnippets: snippetMap[entry.name] || [],
			lifecycle: entry.lifecycle,
		});
	});

	return mergedHooks;
}

function writeGeneratedOutputs({
	docsDir,
	actions,
	filters,
	indexPayload,
	namingAuditPayload,
	deprecatedHooksPayload,
	validateOnly,
}) {
	const generatedDir = path.join(docsDir, 'generated');
	const actionsDir = path.join(docsDir, 'actions');
	const filtersDir = path.join(docsDir, 'filters');
	const shouldPublishHookDoc = (hook) =>
		!hook.isDynamic && !!hook.name && hook.sourceType === 'wpgraphql';
	const shouldListInMainIndex = (hook) =>
		shouldPublishHookDoc(hook) &&
		hook.lifecycle?.status !== 'deprecated' &&
		hook.lifecycle?.status !== 'removed';

	const filesToWrite = [];
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-index.json'),
		content: `${JSON.stringify(indexPayload, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-lint.json'),
		content: `${JSON.stringify(indexPayload.lint, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-lint.md'),
		content: `${renderLintMarkdown({
			pluginSlug: indexPayload.plugin,
			lint: indexPayload.lint,
		})}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-naming-audit.json'),
		content: `${JSON.stringify(namingAuditPayload, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-naming-audit.md'),
		content: `${renderNamingAuditMarkdown({
			pluginSlug: indexPayload.plugin,
			audit: namingAuditPayload.audit,
		})}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-deprecated.json'),
		content: `${JSON.stringify(deprecatedHooksPayload, null, 2)}\n`,
	});
	filesToWrite.push({
		path: path.join(generatedDir, 'hooks-deprecated.md'),
		content: `${renderDeprecatedHooksMarkdown({
			pluginSlug: indexPayload.plugin,
			hooks: deprecatedHooksPayload.hooks,
		})}\n`,
	});
	filesToWrite.push({
		path: path.join(actionsDir, 'index.md'),
		content: renderIndexPage({
			title: 'Actions',
			kind: 'actions',
			hooks: actions.filter(shouldListInMainIndex),
		}),
	});
	filesToWrite.push({
		path: path.join(filtersDir, 'index.md'),
		content: renderIndexPage({
			title: 'Filters',
			kind: 'filters',
			hooks: filters.filter(shouldListInMainIndex),
		}),
	});

	actions
		.filter(shouldPublishHookDoc)
		.forEach((hook) => {
			filesToWrite.push({
				path: path.join(actionsDir, `${slugFromHookName(hook.name)}.md`),
				content: renderHookDoc(hook),
			});
		});

	filters
		.filter(shouldPublishHookDoc)
		.forEach((hook) => {
			filesToWrite.push({
				path: path.join(filtersDir, `${slugFromHookName(hook.name)}.md`),
				content: renderHookDoc(hook),
			});
		});

	const expectedActionsFiles = new Set(
		filesToWrite
			.filter((file) => file.path.startsWith(actionsDir))
			.map((file) => path.basename(file.path))
	);
	const expectedFilterFiles = new Set(
		filesToWrite
			.filter((file) => file.path.startsWith(filtersDir))
			.map((file) => path.basename(file.path))
	);

	if (validateOnly) {
		const changedFiles = filesToWrite
			.filter((file) => fs.existsSync(file.path))
			.filter((file) => fs.readFileSync(file.path, 'utf8') !== file.content)
			.map((file) => path.relative(process.cwd(), file.path));

		const staleFiles = [
			...listMarkdownFiles(actionsDir)
				.filter((filePath) => !expectedActionsFiles.has(path.basename(filePath)))
				.map((filePath) => path.relative(process.cwd(), filePath)),
			...listMarkdownFiles(filtersDir)
				.filter((filePath) => !expectedFilterFiles.has(path.basename(filePath)))
				.map((filePath) => path.relative(process.cwd(), filePath)),
		];

		if (changedFiles.length > 0 || staleFiles.length > 0) {
			const staleSection =
				staleFiles.length > 0
					? `\nStale files:\n${staleFiles.map((item) => `- ${item}`).join('\n')}`
					: '';
			throw new Error(
				`Generated files are stale. Re-run hooks generator. Changed files:\n${changedFiles
					.map((item) => `- ${item}`)
					.join('\n')}${staleSection}`
			);
		}

		return;
	}

	ensureDir(generatedDir);
	ensureDir(actionsDir);
	ensureDir(filtersDir);

	listMarkdownFiles(actionsDir)
		.filter((filePath) => !expectedActionsFiles.has(path.basename(filePath)))
		.forEach((filePath) => fs.unlinkSync(filePath));
	listMarkdownFiles(filtersDir)
		.filter((filePath) => !expectedFilterFiles.has(path.basename(filePath)))
		.forEach((filePath) => fs.unlinkSync(filePath));

	filesToWrite.forEach((file) => {
		fs.writeFileSync(file.path, file.content, 'utf8');
	});
}

function extractHooksFromFile(filePath, repoRoot) {
	const content = fs.readFileSync(filePath, 'utf8');
	const hooks = [];
	const callSpecs = [
		{ functionName: 'do_action_deprecated', kind: 'action', emitter: 'do_action_deprecated' },
		{
			functionName: 'apply_filters_deprecated',
			kind: 'filter',
			emitter: 'apply_filters_deprecated',
		},
		{ functionName: 'do_action', kind: 'action', emitter: 'do_action' },
		{ functionName: 'apply_filters', kind: 'filter', emitter: 'apply_filters' },
	];

	let cursor = 0;
	while (cursor < content.length) {
		const candidates = callSpecs
			.map((spec) => ({
				spec,
				index: content.indexOf(spec.functionName, cursor),
			}))
			.filter((item) => item.index >= 0);
		if (candidates.length === 0) {
			break;
		}

		const next = candidates.sort((a, b) => a.index - b.index)[0];
		const extracted = extractCallAt(content, next.spec.functionName, next.index);

		if (!extracted) {
			cursor = next.index + next.spec.functionName.length;
			continue;
		}

		const args = splitTopLevelArgs(extracted.argsSource);
		const firstArg = args[0] || '';
		const parsedName = parseHookNameExpression(firstArg);
		const docblock = parseDocblock(getNearestDocblock(content, extracted.functionIndex));

		hooks.push({
			name: parsedName.name,
			rawExpression: parsedName.rawExpression,
			isDynamic: parsedName.isDynamic,
			kind: next.spec.kind,
			argumentCount: Math.max(args.length - 1, 0),
			file: path.relative(repoRoot, filePath),
			line: extracted.line,
			sourceCall: extracted.callSource,
			enclosingSymbol: getEnclosingSymbol(content, extracted.functionIndex),
			docblock,
			emitter: next.spec.emitter,
			lifecycle:
				next.spec.emitter === 'do_action_deprecated' ||
				next.spec.emitter === 'apply_filters_deprecated'
					? normalizeDeprecatedCallMetadata(args)
					: null,
		});

		cursor = extracted.endIndex + 1;
	}

	return hooks;
}

function main() {
	const args = parseArgs();
	const repoRoot = process.cwd();
	const pluginSlug = args.plugin;

	if (!pluginSlug) {
		console.error('Error: --plugin is required');
		console.error('Usage: node scripts/hooks/generate-hook-docs.js --plugin=wp-graphql');
		process.exit(1);
	}

	const configPath = args.config
		? path.resolve(repoRoot, args.config)
		: path.resolve(repoRoot, 'scripts/hooks/plugin-config.json');
	const groupsPath = args.groups
		? path.resolve(repoRoot, args.groups)
		: path.resolve(repoRoot, 'scripts/hooks/groups.json');
	const namingRulesPath = args['naming-rules']
		? path.resolve(repoRoot, args['naming-rules'])
		: path.resolve(repoRoot, 'scripts/hooks/naming-rules.json');
	const legacyHooksPath = args['legacy-hooks']
		? path.resolve(repoRoot, args['legacy-hooks'])
		: path.resolve(repoRoot, 'scripts/hooks/legacy-hooks.json');

	const pluginConfigMap = readJson(configPath);
	const groups = readJson(groupsPath);
	const namingRules = fs.existsSync(namingRulesPath)
		? readJson(namingRulesPath)
		: getDefaultNamingRules();
	const legacyHooks = fs.existsSync(legacyHooksPath)
		? loadLegacyHooks(legacyHooksPath, pluginSlug)
		: getDefaultLegacyHooks()[pluginSlug] || [];
	const pluginConfig = pluginConfigMap[pluginSlug];
	const validateOnly = args['validate-only'] === 'true' || args['validate-only'] === true;
	const requireExplicitGroup =
		args['require-explicit-group'] === 'true' || args['require-explicit-group'] === true;

	if (!pluginConfig) {
		console.error(`Error: Plugin "${pluginSlug}" not found in ${configPath}`);
		process.exit(1);
	}

	const pluginDir = path.resolve(repoRoot, pluginConfig.pluginDir);
	const docsDir = path.resolve(repoRoot, pluginConfig.docsDir);
	const snippetsDir = path.resolve(repoRoot, pluginConfig.snippetsDir || '');
	const repositoryUrl = resolveRepositoryUrl({ args, pluginConfig, repoRoot });
	const repositoryRef = resolveRepositoryRef({ args, pluginConfig, repoRoot });

	const sourcePaths = Array.isArray(pluginConfig.sourcePaths) ? pluginConfig.sourcePaths : ['src'];
	const phpFiles = [];
	sourcePaths.forEach((sourcePath) => {
		const fullPath = path.resolve(pluginDir, sourcePath);
		walkPhpFiles(fullPath, phpFiles);
	});

	const snippets = loadSnippets(snippetsDir);
	const recipeRelations = loadRecipeRelations(docsDir);
	let hookRecords = [];
	const lint = {
		errors: [],
		warnings: [],
	};

	phpFiles.forEach((phpFile) => {
		const extractedHooks = extractHooksFromFile(phpFile, repoRoot);
		extractedHooks.forEach((hook) => {
			const groupAssignment = assignGroup(hook, groups);
			const sourceType = inferHookSourceType(hook, namingRules);
			const record = buildHookRecord({
				pluginSlug,
				hook,
				groupAssignment,
				sourceType,
				relativeFilePath: hook.file,
				snippetMap: snippets.byHookName,
				repositoryUrl,
				repositoryRef,
			});

			const shouldLintHookGroup =
				hook.emitter === 'do_action' || hook.emitter === 'apply_filters';

			if (
				shouldLintHookGroup &&
				sourceType === 'wpgraphql' &&
				hook.docblock.hookGroup &&
				groupAssignment.source === 'invalid'
			) {
				lint.errors.push({
					type: 'invalid_hook_group',
					hook: hook.name,
					file: hook.file,
					line: hook.line,
					message: `Invalid @hookGroup "${hook.docblock.hookGroup}"`,
				});
			}

			if (shouldLintHookGroup && sourceType === 'wpgraphql' && !hook.docblock.hookGroup) {
				const warning = {
					type: 'missing_hook_group',
					hook: hook.name,
					file: hook.file,
					line: hook.line,
					message: 'Missing @hookGroup tag',
				};
				if (requireExplicitGroup) {
					lint.errors.push(warning);
				} else {
					lint.warnings.push(warning);
				}
			}

			if (shouldLintHookGroup && sourceType === 'wpgraphql') {
				if (!hook.docblock.since || !hook.docblock.since.trim()) {
					lint.warnings.push({
						type: 'missing_hook_since',
						hook: hook.name,
						file: hook.file,
						line: hook.line,
						message: 'Missing @since tag in nearest docblock',
					});
				}

				if (!hook.docblock.description || !hook.docblock.description.trim()) {
					lint.warnings.push({
						type: 'missing_hook_description',
						hook: hook.name,
						file: hook.file,
						line: hook.line,
						message: 'Missing hook description in nearest docblock',
					});
				}

				const argumentCount = hook.argumentCount || 0;
				const paramCount = hook.docblock.params.length;

				if (argumentCount > 0 && paramCount === 0) {
					lint.warnings.push({
						type: 'missing_hook_params',
						hook: hook.name,
						file: hook.file,
						line: hook.line,
						message:
							'Hook receives arguments but docblock is missing @param entries',
					});
				}

				if (argumentCount > 0 && paramCount > 0 && paramCount < argumentCount) {
					lint.warnings.push({
						type: 'hook_param_count_mismatch',
						hook: hook.name,
						file: hook.file,
						line: hook.line,
						message: `Hook has ${argumentCount} argument(s) but only ${paramCount} @param tag(s)`,
					});
				}

				hook.docblock.params.forEach((param, index) => {
					if (!param.description || !param.description.trim()) {
						lint.warnings.push({
							type: 'missing_hook_param_description',
							hook: hook.name,
							file: hook.file,
							line: hook.line,
							message: `@param entry ${index + 1} (${param.name}) is missing a description`,
						});
					}
				});
			}

			hookRecords.push(record);
		});
	});

	hookRecords = mergeLegacyHooks({
		hooks: hookRecords,
		legacyEntries: legacyHooks,
		groups,
		snippetMap: snippets.byHookName,
		pluginSlug,
	});
	hookRecords = attachRelatedReferences(hookRecords);
	hookRecords = hookRecords.map((hook) => {
		if (!hook.name) {
			return {
				...hook,
				relatedRecipes: [],
			};
		}

		const relatedRecipes =
			hook.kind === 'action'
				? recipeRelations.byAction[hook.name] || []
				: recipeRelations.byFilter[hook.name] || [];

		return {
			...hook,
			relatedRecipes,
		};
	});

	const actions = hookRecords.filter((hook) => hook.kind === 'action');
	const filters = hookRecords.filter((hook) => hook.kind === 'filter');
	const deprecatedHooksByKey = new Map();
	hookRecords
		.filter((hook) => {
			const status = hook.lifecycle?.status;
			return (status === 'deprecated' || status === 'removed') && !hook.isDynamic && !!hook.name;
		})
		.forEach((hook) => {
			const key = `${hook.kind}:${hook.name}`;
			const existing = deprecatedHooksByKey.get(key);
			if (!existing) {
				deprecatedHooksByKey.set(key, {
					...hook,
					sourceLocations: [{ file: hook.file, line: hook.line }],
					occurrences: 1,
				});
				return;
			}

			existing.occurrences += 1;
			existing.sourceLocations.push({ file: hook.file, line: hook.line });
			if (
				existing.lifecycle &&
				!existing.lifecycle.deprecatedIn &&
				hook.lifecycle &&
				hook.lifecycle.deprecatedIn
			) {
				existing.lifecycle.deprecatedIn = hook.lifecycle.deprecatedIn;
			}
		});
	const deprecatedHooks = Array.from(deprecatedHooksByKey.values()).sort((a, b) =>
		(a.name || '').localeCompare(b.name || '')
	);
	const namingAudit = analyzeHookNaming(hookRecords, namingRules);

	const payload = {
		plugin: pluginSlug,
		generatedAt: new Date().toISOString(),
		stats: {
			totalHooks: hookRecords.length,
			actions: actions.length,
			filters: filters.length,
			dynamic: hookRecords.filter((hook) => hook.isDynamic).length,
			snippets: snippets.total,
		},
		groups,
		lint,
		namingAudit: {
			flaggedHooks: namingAudit.summary.flaggedHooks,
			warnings: namingAudit.summary.warnings,
			errors: namingAudit.summary.errors,
			wpgraphqlHooks: namingAudit.summary.wpgraphqlHooks,
			coreHooks: namingAudit.summary.coreHooks,
		},
		hooks: hookRecords.sort((a, b) => {
			const nameCompare = (a.name || '').localeCompare(b.name || '');
			if (nameCompare !== 0) {
				return nameCompare;
			}
			return a.file.localeCompare(b.file);
		}),
	};
	const namingAuditPayload = {
		plugin: pluginSlug,
		generatedAt: payload.generatedAt,
		audit: namingAudit,
	};
	const deprecatedHooksPayload = {
		plugin: pluginSlug,
		generatedAt: payload.generatedAt,
		count: deprecatedHooks.length,
		hooks: deprecatedHooks,
	};

	namingAudit.flaggedHooks.forEach((flag) => {
		lint.warnings.push({
			type: 'naming_convention',
			hook: flag.hook,
			file: flag.file,
			line: flag.line,
			message: `${flag.code}: ${flag.message}`,
		});
	});

	writeGeneratedOutputs({
		docsDir,
		actions,
		filters,
		indexPayload: payload,
		namingAuditPayload,
		deprecatedHooksPayload,
		validateOnly,
	});

	if (lint.warnings.length > 0) {
		console.warn(`Warnings: ${lint.warnings.length}`);
	}

	if (lint.errors.length > 0) {
		console.error(`Errors: ${lint.errors.length}`);
		process.exit(1);
	}

	console.log(
		`Generated hook docs for ${pluginSlug}: ${actions.length} actions, ${filters.length} filters`
	);
}

if (require.main === module) {
	main();
}

module.exports = {
	analyzeHookNaming,
	assignGroup,
	extractHooksFromFile,
	getDefaultNamingRules,
	inferHookSourceType,
	parseDocblock,
	parseFrontmatter,
	parseHookNameExpression,
	renderNamingAuditMarkdown,
	splitTopLevelArgs,
};
